import { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import API from "../../services/api";
import "./css/AdminDashboard.css"; // We created this beautiful CSS

function AdminDashboard() {
  const [stats, setStats] = useState({
    open_vacancies: 0,
    resumes_scanned: 0,
    top_matches: 0,
    alerts_sent: 0
  });

  const [jobTitle, setJobTitle] = useState("");
  const [skills, setSkills] = useState("");
  const [minCgpa, setMinCgpa] = useState("");
  const [jobType, setJobType] = useState("");

  const [liveCandidates, setLiveCandidates] = useState([]);
  const [isPosting, setIsPosting] = useState(false);

  // Fetch initial stats
  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const res = await API.get("/admin/dashboard-stats");
      setStats(res.data);
    } catch (error) {
      console.error("Error fetching stats:", error);
    }
  };

  const handlePostJob = async (e) => {
    e.preventDefault();
    setIsPosting(true);
    try {
      const res = await API.post("/admin/post-job", {
        title: jobTitle,
        skills: skills,
        min_cgpa: minCgpa,
        job_type: jobType
      });

      // Update Live Candidates table natively without full reload
      if(res.data && res.data.matches) {
         setLiveCandidates(res.data.matches);
         // Optionally refresh stats immediately
         fetchStats();
      }

      alert(res.data.message || "Job posted successfully!");
      // Reset form (optional)
      setJobTitle("");
      setSkills("");
      setMinCgpa("");
      setJobType("");

    } catch (error) {
      console.error(error);
      alert("Failed to post job");
    } finally {
      setIsPosting(false);
    }
  };

  // Helper for generating random avatars (like the animals in mockup)
  const getAvatarAndColor = (index) => {
    const options = [
      { emoji: "🦊", color: "bg-orange-subtle" },
      { emoji: "🐼", color: "bg-purple-subtle" },
      { emoji: "🐨", color: "bg-gray-subtle" },
      { emoji: "🦁", color: "bg-orange-subtle" }
    ];
    return options[index % options.length];
  };

  return (
    <div className="dashboard-layout">
      {/* Sidebar Navigation */}
      <aside className="dashboard-sidebar">
        <div className="sidebar-logo">
          <div className="logo-icon" style={{background: '#3b82f6'}}>📄</div>
          ResumeAlert 💡
        </div>

        <nav className="nav-menu">
          <Link to="/admin/dashboard" className="nav-link active">
            🏠 Dashboard
          </Link>
          <Link to="#" className="nav-link">
            📁 Job Vacancies
          </Link>
          <Link to="#" className="nav-link">
            🔍 Resume Scans
          </Link>
          <Link to="#" className="nav-link">
            📧 Email Logs
          </Link>
          <Link to="#" className="nav-link">
            ⚙️ Preferences
          </Link>
        </nav>

        <div className="profile-status" style={{background: '#f8fafc', border: '1px solid #f1f5f9'}}>
          <div className="status-header" style={{color: '#94a3b8'}}>AUTOMATED SYSTEM</div>
          <div className="status-text">
            <span>Auto-Matching</span>
            <span className="status-dot"></span>
          </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="dashboard-main">

        {/* Header */}
        <header className="admin-header-flex">
          <div className="admin-title-area">
            <h1>Smart Monitoring Dashboard 🤖 📊</h1>
            <p>Matching job criteria with user resumes in real-time. ✨</p>
          </div>

          <div className="header-tools">
            <button className="admin-post-btn">
              <span>+</span> Post Job Vacancy
            </button>
            <div className="notification-bell">
              🔔
              <span className="notification-badge" style={{background: '#ef4444'}}>3</span>
            </div>
          </div>
        </header>

        {/* Top Stat Cards */}
        <div className="admin-stats-grid">
          <div className="admin-stat-card">
            <div className="stat-label-row">OPEN VACANCIES 📁</div>
            <div className="stat-value-large">{stats.open_vacancies}</div>
            <div className="stat-metric-pill pill-blue">3 added today</div>
          </div>

          <div className="admin-stat-card">
            <div className="stat-label-row">RESUMES SCANNED 📄</div>
            <div className="stat-value-large">{stats.resumes_scanned}</div>
            <div className="stat-metric-pill pill-green">Real-time Sync</div>
          </div>

          <div className="admin-stat-card">
             <div className="stat-label-row">TOP MATCHES 🎯</div>
            <div className="stat-value-large">{stats.top_matches}</div>
            <div className="stat-metric-pill pill-yellow">High CGPA + Skills</div>
          </div>

          <div className="admin-stat-card">
             <div className="stat-label-row">ALERTS SENT 📧</div>
            <div className="stat-value-large">{stats.alerts_sent}</div>
            <div className="stat-metric-pill pill-purple">Auto-triggered</div>
          </div>
        </div>

        {/* Post Vacancy Form */}
        <div className="vacancy-form-card">
          <div className="form-title">Post New Vacancy 📢</div>

          <form onSubmit={handlePostJob}>
            <input 
              className="admin-input" 
              placeholder="Job Title (e.g. React Developer)" 
              value={jobTitle}
              onChange={(e) => setJobTitle(e.target.value)}
              required
            />

            <textarea 
              className="admin-input admin-textarea" 
              placeholder="Required Skills (Comma separated)"
              value={skills}
              onChange={(e) => setSkills(e.target.value)}
              required
            ></textarea>

            <div className="grid-2-cols">
              <input 
                className="admin-input" 
                placeholder="Min CGPA" 
                type="number"
                step="0.01"
                min="0"
                max="4.0"
                value={minCgpa}
                onChange={(e) => setMinCgpa(e.target.value)}
              />
              <input 
                className="admin-input" 
                placeholder="Full Time" 
                value={jobType}
                onChange={(e) => setJobType(e.target.value)}
              />
            </div>

            <button type="submit" className="form-submit-dark" disabled={isPosting}>
              {isPosting ? "Processing..." : "Upload & Trigger Matching 🚀"}
            </button>
          </form>
        </div>

        {/* Smart Tips Box */}
        <div className="auth-card-modern" style={{width: '100%', maxWidth: '100%', background: 'linear-gradient(135deg, #3b82f6, #4f46e5)', color: 'white', marginBottom: '2.5rem', padding: '2rem'}}>
          <h3 style={{marginBottom: '0.5rem', color: 'white'}}>Smart Tips 💡</h3>
          <p style={{color: 'rgba(255,255,255,0.9)', marginBottom: '1rem'}}>
            The AI matches keywords in resumes and verifies CGPA before sending an alert. Accuracy is currently at 98%! 🎯
          </p>
          <button style={{background: 'none', border: 'none', padding: 0, font: 'inherit', color: 'white', fontWeight: 'bold', textDecoration: 'underline', cursor: 'pointer'}}>LEARN MORE</button>
        </div>

        {/* Live Eligible Candidates Table */}
        <div className="candidates-card">
          <div className="candidates-header">
             <div className="candidates-title">
               <h2>Live Eligible Candidates 🎓</h2>
               <p>Automatic matching based on vacancy criteria 🦄</p>
             </div>
             <button className="refresh-btn">REFRESHING...</button>
          </div>

          {liveCandidates.length === 0 ? (
             <div style={{textAlign: 'center', padding: '2rem', color: '#94a3b8'}}>
               No matching candidates yet. Post a job to see real-time matches!
             </div>
          ) : (
            <table className="table-layout">
              <thead>
                <tr>
                  <th>CANDIDATE 👤</th>
                  <th>SKILL MATCH 🧩</th>
                  <th>CGPA 📚</th>
                  <th>ALERT STATUS 📧</th>
                </tr>
              </thead>
              <tbody>
                {liveCandidates.map((candidate, index) => {
                  const uiTheme = getAvatarAndColor(index);
                  const isHighMatch = candidate.match_score >= 80;

                  return (
                    <tr key={index}>
                      <td>
                        <div className="candidate-profile">
                          <div className={`candidate-avatar ${uiTheme.color}`}>
                            {uiTheme.emoji}
                          </div>
                          <div className="candidate-info">
                            <h4>{candidate.name}</h4>
                            <p>Applied: React Dev</p>
                          </div>
                        </div>
                      </td>
                      <td>
                        <div className="skill-bar-container">
                          <div className="skill-bar-bg">
                            <div 
                              className="skill-bar-fill" 
                              style={{
                                width: `${candidate.match_score}%`,
                                backgroundColor: isHighMatch ? '#10b981' : '#3b82f6'
                              }}
                            ></div>
                          </div>
                          <div 
                            className="skill-text" 
                            style={{color: isHighMatch ? '#10b981' : '#3b82f6'}}
                          >
                            {candidate.match_score}% Match
                          </div>
                        </div>
                      </td>
                      <td>
                        <div className="cgpa-display">{candidate.cgpa}</div>
                      </td>
                      <td>
                        {candidate.status === "Email Sent" ? (
                          <div className="status-badge badge-green">
                            EMAIL SENT ☑️
                          </div>
                        ) : (
                          <div className="status-badge badge-red">
                            INELIGIBLE ❌
                          </div>
                        )}
                      </td>
                    </tr>
                  )
                })}
              </tbody>
            </table>
          )}
        </div>

      </main>
    </div>
  );
}

export default AdminDashboard;
